def run(ctx, command, stream, execute, no_verify, no_decompose):
    """
    Run a command through the BDH engine.

    Example: bdh run "make me a simple Python web server"
    """
    config = ctx.obj['config']

    if no_verify:
        config.verify_outputs = False
    if no_decompose:
        config.decompose_tasks = False

    command_str = " ".join(command)

    try:
        engine = BDHEngine(config=config, verbose=ctx.obj['verbose'])
        result = engine.process_command(command_str, stream=stream, execute_code=execute)

        if not stream:
            click.echo(result)

        engine.close()

    except KeyboardInterrupt:
        click.echo("\nInterrupted.")
    except Exception as e:
        click.echo(f"Error: {e}", err=True)
        if ctx.obj['verbose']:
            import traceback
            traceback.print_exc()

