def handle_special_command(self, command: str) -> bool:
        """
        Handle a special command.

        Returns:
            True if should continue REPL, False if should exit
        """
        cmd = command.lower().strip()

        if cmd in ('/quit', '/exit'):
            self.save_state()
            return False

        elif cmd == '/help':
            self.print_help()

        elif cmd == '/clear':
            self.claude.clear_history() if self.claude else None
            self.state_manager.memory_graph.clear()
            self.print_success("Cleared conversation history and graph.")

        elif cmd == '/graph':
            summary = self.state_manager.memory_graph.get_summary()
            print(f"\n{summary}\n")

        elif cmd == '/stats':
            self.print_stats()

        elif cmd == '/save':
            self.save_state()
            self.print_success("State saved.")

        elif cmd == '/history':
            if self.history:
                print("\nRecent commands:")
                for i, h in enumerate(self.history[-10:], 1):
                    print(f"  {i}. {h[:60]}{'...' if len(h) > 60 else ''}")
                print()
            else:
                print("No command history.")

        elif cmd == '/exec':
            if self.last_response:
                self.execute_code_in_response(self.last_response)
            else:
                self.print_warning("No previous response to execute.")

        elif cmd == '/verify':
            if self.last_response:
                self.verify_response(self.last_response)
            else:
                self.print_warning("No previous response to verify.")

        elif cmd == '/context':
            context = self.state_manager.get_context_summary()
            print(f"\n{context}\n")

        elif cmd == '/sessions':
            sessions = self.state_manager.list_sessions()
            if sessions:
                print("\nSessions:")
                for s in sessions:
                    marker = "→" if s.session_id == (self.state_manager.current_session.session_id if self.state_manager.current_session else "") else " "
                    print(f"  {marker} {s.name} ({s.session_id[:8]}...) - {s.interaction_count} interactions")
                print()
            else:
                print("No sessions found.")

        elif cmd == '/new':
            self.state_manager.create_session(name="repl_new")
            self.print_success("Started new session.")

        elif cmd == '/stream':
            self.streaming = not self.streaming
            self.print_info(f"Streaming: {'ON' if self.streaming else 'OFF'}")

        elif cmd == '/verbose':
            self.verbose = not self.verbose
            self.print_info(f"Verbose: {'ON' if self.verbose else 'OFF'}")

        else:
            self.print_warning(f"Unknown command: {command}")
            self.print_info("Type /help for available commands.")

        return True

