def execute_code_in_response(self, response: str):
        """Execute code blocks in the response."""
        code_blocks = self.executor.extract_code_blocks(response)

        if not code_blocks:
            self.print_warning("No code blocks found in the last response.")
            return

        for i, (lang, code) in enumerate(code_blocks, 1):
            print(f"\n📋 Executing code block {i} ({lang})...")
            print("-" * 40)
            print(code[:200] + ("..." if len(code) > 200 else ""))
            print("-" * 40)

            # Confirm execution
            confirm = input("Execute? [y/N] ").strip().lower()
            if confirm != 'y':
                continue

            result = self.executor.execute(code, lang)

            if result.success:
                self.print_success(f"✅ Execution successful ({result.execution_time:.2f}s)")
                if result.output:
                    print(f"\nOutput:\n{result.output}")
            else:
                self.print_error(f"❌ Execution failed")
                print(f"\nError:\n{result.error}")

