def _extract_code_elements(self, text: str) -> List[ExtractedConcept]:
        """Extract code-related concepts."""
        concepts = []

        for element_type, pattern in self.CODE_PATTERNS.items():
            matches = re.findall(pattern, text, re.IGNORECASE)
            for match in matches:
                if isinstance(match, tuple):
                    match = match[0]
                if match and len(match) > 1:
                    concepts.append(ExtractedConcept(
                        text=match,
                        concept_type="code",
                        confidence=0.95,
                        metadata={"code_type": element_type}
                    ))

        return concepts

