def summarize_extraction(self, result: ExtractionResult) -> str:
        """Create a human-readable summary of extraction."""
        lines = [f"Extracted {len(result.concepts)} concepts:"]

        # Group by type
        by_type = {}
        for c in result.concepts:
            by_type.setdefault(c.concept_type, []).append(c.text)

        for ctype, concepts in by_type.items():
            lines.append(f"  {ctype}: {', '.join(concepts[:10])}")
            if len(concepts) > 10:
                lines.append(f"    ... and {len(concepts) - 10} more")

        if result.relations:
            lines.append(f"\nExtracted {len(result.relations)} relations:")
            for rel in result.relations[:5]:
                lines.append(f"  {rel.source} --[{rel.relation_type}]--> {rel.target}")
            if len(result.relations) > 5:
                lines.append(f"  ... and {len(result.relations) - 5} more")

        return "\n".join(lines)

