def _from_template(self, task_type: str, command: str) -> List[Subtask]:
        """Create subtasks from a template."""
        template = self.TASK_TEMPLATES.get(task_type, [])
        subtasks = []

        # Map task names to IDs for dependencies
        task_name_to_id = {}

        for i, (title, _) in enumerate(template, 1):
            task_name_to_id[title.lower()] = i

        for i, (title, dep_names) in enumerate(template, 1):
            # Resolve dependencies
            dependencies = []
            for dep in dep_names:
                # Find a matching task
                for name, tid in task_name_to_id.items():
                    if dep.lower() in name:
                        dependencies.append(tid)
                        break

            subtasks.append(Subtask(
                id=i,
                title=title,
                description=f"Part of: {command[:50]}...",
                priority=TaskPriority.MEDIUM,
                dependencies=dependencies
            ))

        return subtasks

