def _simple_decompose(self, command: str) -> DecompositionResult:
        """Simple fallback decomposition."""
        subtasks = []

        # Check for numbered list in command
        numbered = re.findall(r'(\d+[.)]\s*[^\d]+)', command)
        if numbered:
            for i, item in enumerate(numbered, 1):
                title = re.sub(r'^\d+[.)]\s*', '', item).strip()
                subtasks.append(Subtask(
                    id=i,
                    title=title[:100],
                    description=title
                ))
            return DecompositionResult(
                original_command=command,
                subtasks=subtasks,
                complexity_score=0.3
            )

        # Check for comma/semicolon separated items
        for sep in [';', ', and ', ', ']:
            if sep in command:
                parts = command.split(sep)
                if 2 <= len(parts) <= 10:
                    for i, part in enumerate(parts, 1):
                        part = part.strip()
                        if part:
                            subtasks.append(Subtask(
                                id=i,
                                title=part[:100],
                                description=part
                            ))
                    return DecompositionResult(
                        original_command=command,
                        subtasks=subtasks,
                        complexity_score=0.3
                    )

        # Default: treat as single task
        return DecompositionResult(
            original_command=command,
            subtasks=[Subtask(
                id=1,
                title=command[:100],
                description=command,
                estimated_complexity="high"
            )],
            complexity_score=self._estimate_complexity(command)
        )

