def _check_code(self, output: str) -> List[Issue]:
        """Check code for common errors."""
        issues = []

        # Detect language
        language = self._detect_language(output)

        if language in self.CODE_ERROR_PATTERNS:
            for pattern, description in self.CODE_ERROR_PATTERNS[language]:
                matches = re.finditer(pattern, output, re.MULTILINE)
                for match in matches:
                    issues.append(Issue(
                        severity="low" if "style" in description.lower() else "medium",
                        category="code_error",
                        description=description,
                        location=match.group(0)[:50]
                    ))

        # Check for syntax errors (basic)
        code_blocks = self._extract_code_blocks(output)
        for lang, code in code_blocks:
            if lang == "python":
                syntax_error = self._check_python_syntax(code)
                if syntax_error:
                    issues.append(Issue(
                        severity="high",
                        category="code_error",
                        description=f"Python syntax error: {syntax_error}"
                    ))

        return issues

