        """Check for uncertainty markers."""
        issues = []

        for pattern in self.UNCERTAINTY_MARKERS:
            matches = re.findall(pattern, output, re.IGNORECASE)
            if matches:
                issues.append(Issue(
                    severity="low",
                    category="uncertainty",
                    description=f"Contains uncertainty marker: {matches[0]}",
                    suggestion="Verify this information independently"
                ))

        return issues

