def _verify_with_claude(
        self,
        output: str,
        original_command: Optional[str],
        context: Optional[str],
        output_type: str
    ) -> Optional[Dict]:
        """Use Claude for verification."""
        if not self.claude_client:
            return None

        prompt = f"""Verify this output for:
1. Hallucinations (invented APIs, functions, facts)
2. Code errors (if code is present)
3. Logical inconsistencies
4. Factual accuracy

Output to verify:
```
{output[:3000]}
```

{"Original request: " + original_command[:200] if original_command else ""}

Respond with JSON:
{{
    "status": "passed|needs_review|failed",
    "issues": [
        {{"severity": "low|medium|high", "category": "category", "description": "issue"}}
    ],
    "suggestions": ["suggestion1", "suggestion2"]
}}"""

        try:
            result = self.claude_client.call_for_json(
                prompt,
                context=context,
                task_type="verify",
                default=None
            )

            if result and isinstance(result, dict):
                # Convert issues to Issue objects
                issues = []
                for issue_data in result.get("issues", []):
                    if isinstance(issue_data, dict):
                        issues.append(Issue(
                            severity=issue_data.get("severity", "medium"),
                            category=issue_data.get("category", "general"),
                            description=issue_data.get("description", "Unknown issue")
                        ))

                return {
                    "issues": issues,
                    "suggestions": result.get("suggestions", [])
                }
        except Exception:
            pass

        return None

_determine_status.code:
def _determine_status(self, issues: List[Issue]) -> VerificationStatus:
        """Determine overall verification status."""
        if not issues:
            return VerificationStatus.PASSED

        severity_counts = {}
        for issue in issues:
            severity_counts[issue.severity] = severity_counts.get(issue.severity, 0) + 1

        if severity_counts.get("critical", 0) > 0:
            return VerificationStatus.FAILED
        if severity_counts.get("high", 0) > 0:
            return VerificationStatus.NEEDS_REVIEW
        if severity_counts.get("medium", 0) > 2:
            return VerificationStatus.NEEDS_REVIEW

        return VerificationStatus.PASSED

_calculate_confidence.code:
def _calculate_confidence(self, issues: List[Issue], output: str) -> float:
        """Calculate confidence score for the output."""
        base_confidence = 1.0

        # Reduce for each issue
        for issue in issues:
            if issue.severity == "critical":
                base_confidence -= 0.3
            elif issue.severity == "high":
                base_confidence -= 0.15
            elif issue.severity == "medium":
                base_confidence -= 0.05
            elif issue.severity == "low":
                base_confidence -= 0.02

        # Reduce for very short or very long outputs
        if len(output) < 50:
            base_confidence -= 0.1
        if len(output) > 10000:
            base_confidence -= 0.05

        return max(0.0, min(1.0, base_confidence))

