def _detect_language(self, text: str) -> str:
        """Detect programming language in text."""
        patterns = {
            'python': [r'def\s+\w+', r'import\s+\w+', r'from\s+\w+\s+import'],
            'javascript': [r'const\s+\w+', r'let\s+\w+', r'function\s+\w+', r'=>'],
            'java': [r'public\s+class', r'private\s+\w+', r'void\s+\w+\('],
            'cpp': [r'#include\s*<', r'int\s+main\s*\(', r'std::'],
            'rust': [r'fn\s+\w+', r'let\s+mut', r'impl\s+']
        }

        scores = {}
        for lang, lang_patterns in patterns.items():
            score = sum(1 for p in lang_patterns if re.search(p, text))
            if score > 0:
                scores[lang] = score

        if scores:
            return max(scores, key=scores.get)

        return "unknown"

