def get_summary(self, result: VerificationResult) -> str:
        """Get a human-readable summary of verification."""
        lines = [f"Verification Status: {result.status.value.upper()}"]
        lines.append(f"Confidence: {result.confidence:.1%}")

        if result.issues:
            lines.append(f"\nIssues Found: {len(result.issues)}")
            for issue in result.issues[:5]:
                lines.append(f"  [{issue.severity.upper()}] {issue.category}: {issue.description}")
            if len(result.issues) > 5:
                lines.append(f"  ... and {len(result.issues) - 5} more")

        if result.suggestions:
            lines.append("\nSuggestions:")
            for suggestion in result.suggestions[:3]:
                lines.append(f"  - {suggestion}")

        return "\n".join(lines)

