def _load_from_env(self):
        """Load configuration from environment variables."""
        # Load from .env file if it exists
        env_file = self.project_root / ".env"
        if env_file.exists():
            self._parse_env_file(env_file)

        # API Key
        self.api_key = os.getenv("ANTHROPIC_API_KEY", self.api_key)

        # Model settings
        if os.getenv("BDH_MODEL_NAME"):
            self.model.model_name = os.getenv("BDH_MODEL_NAME")
        if os.getenv("BDH_MAX_TOKENS"):
            self.model.max_tokens = int(os.getenv("BDH_MAX_TOKENS"))
        if os.getenv("BDH_TEMPERATURE"):
            self.model.temperature = float(os.getenv("BDH_TEMPERATURE"))

        # Hebbian settings
        if os.getenv("BDH_LEARNING_RATE"):
            self.hebbian.learning_rate = float(os.getenv("BDH_LEARNING_RATE"))
        if os.getenv("BDH_DECAY_RATE"):
            self.hebbian.decay_rate = float(os.getenv("BDH_DECAY_RATE"))

        # State settings
        if os.getenv("BDH_DB_FILE"):
            self.state.db_file = os.getenv("BDH_DB_FILE")

        # Behavior settings
        if os.getenv("BDH_VERIFY_OUTPUTS"):
            self.verify_outputs = os.getenv("BDH_VERIFY_OUTPUTS").lower() == "true"
        if os.getenv("BDH_VERBOSE"):
            self.verbose = os.getenv("BDH_VERBOSE").lower() == "true"
        if os.getenv("BDH_DEBUG"):
            self.debug = os.getenv("BDH_DEBUG").lower() == "true"

_parse_env_file.code:
def _parse_env_file(self, env_file: Path):
        """Parse a .env file and set environment variables."""
        with open(env_file, 'r') as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith('#') and '=' in line:
                    key, value = line.split('=', 1)
                    key = key.strip()
                    value = value.strip().strip('"').strip("'")
                    os.environ.setdefault(key, value)

